import{f as a,o as e,c as r,a2 as d}from"./chunks/framework.DHYrF-q6.js";const b=JSON.parse('{"title":"Java 高级","description":"","frontmatter":{},"headers":[],"relativePath":"java-advanced/index.md","filePath":"java-advanced/index.md","lastUpdated":1780734044000}'),l={name:"java-advanced/index.md"};function i(o,t,s,h,n,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="java-高级" tabindex="-1">Java 高级 <a class="header-anchor" href="#java-高级" aria-label="Permalink to &quot;Java 高级&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>Java 高级模块覆盖后端开发的核心基础能力，从 JVM 底层原理到并发编程、集合框架、IO 模型以及设计模式，是面试中考察深度和广度最集中的领域。本模块旨在帮助开发者从&quot;会用&quot;进阶到&quot;精通&quot;，建立对 Java 技术栈的系统性认知。</p><div class="tip custom-block"><p class="custom-block-title">适用人群</p><p>具备 1-3 年 Java 开发经验，正在准备中大厂面试的开发者。</p></div><div class="info custom-block"><p class="custom-block-title">模块定位</p><p>深入原理层面，强调源码解读、场景分析和性能调优。</p></div><h2 id="核心知识点" tabindex="-1">核心知识点 <a class="header-anchor" href="#核心知识点" aria-label="Permalink to &quot;核心知识点&quot;">​</a></h2><h3 id="jvm-虚拟机" tabindex="-1">JVM 虚拟机 <a class="header-anchor" href="#jvm-虚拟机" aria-label="Permalink to &quot;JVM 虚拟机&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>内存模型</td><td>堆、栈、方法区、元空间结构；对象创建与内存分配策略</td></tr><tr><td>垃圾回收</td><td>GC 算法（标记-清除、标记-整理、复制、分代）；CMS / G1 / ZGC 原理与调优</td></tr><tr><td>类加载</td><td>双亲委派机制、打破双亲委派（Tomcat/SPI）、自定义类加载器</td></tr><tr><td>性能调优</td><td>JVM 参数配置、内存泄漏排查、MAT / Arthas / jstack 实战</td></tr></tbody></table><h3 id="并发编程" tabindex="-1">并发编程 <a class="header-anchor" href="#并发编程" aria-label="Permalink to &quot;并发编程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>基础理论</td><td>线程生命周期、上下文切换、死锁的条件与排查</td></tr><tr><td>JUC 核心</td><td>AQS 原理、ReentrantLock / synchronized 底层对比、CountDownLatch / CyclicBarrier / Semaphore</td></tr><tr><td>线程池</td><td>ThreadPoolExecutor 参数详解、拒绝策略、ForkJoinPool、CompletableFuture</td></tr><tr><td>并发容器</td><td>ConcurrentHashMap 源码分段锁演进、CopyOnWriteArrayList、BlockingQueue</td></tr><tr><td>原子类</td><td>CAS 原理、ABA 问题、LongAdder 分段思想</td></tr></tbody></table><h3 id="集合框架" tabindex="-1">集合框架 <a class="header-anchor" href="#集合框架" aria-label="Permalink to &quot;集合框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>List</td><td>ArrayList vs LinkedList 底层差异、扩容机制、fail-fast 原理</td></tr><tr><td>Map</td><td>HashMap 1.7 vs 1.8 红黑树演进、扩容死循环分析、LinkedHashMap LRU 实现</td></tr><tr><td>Set</td><td>HashSet / TreeSet 底层依赖、Comparable vs Comparator</td></tr></tbody></table><h3 id="io-与网络" tabindex="-1">IO 与网络 <a class="header-anchor" href="#io-与网络" aria-label="Permalink to &quot;IO 与网络&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>BIO/NIO/AIO</td><td>阻塞与非阻塞模型对比、Buffer / Channel / Selector 三件套</td></tr><tr><td>Netty</td><td>Reactor 模型、Pipeline 责任链、零拷贝、粘包拆包解决方案</td></tr><tr><td>序列化</td><td>JDK 序列化缺陷、Protobuf / Kryo / Hessian 对比</td></tr></tbody></table><h3 id="设计模式" tabindex="-1">设计模式 <a class="header-anchor" href="#设计模式" aria-label="Permalink to &quot;设计模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>创建型</td><td>单例（双重校验/DCL/枚举）、工厂/抽象工厂、建造者</td></tr><tr><td>结构型</td><td>代理（JDK 动态代理 vs CGLIB）、装饰器、适配器（Spring MVC 中的体现）</td></tr><tr><td>行为型</td><td>观察者、策略、模板方法（Spring 中大量使用）、责任链</td></tr><tr><td>应用</td><td>Spring/MyBatis 源码中的设计模式实例</td></tr></tbody></table><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>HashMap 源码</strong>：为什么容量是 2 的幂？红黑树转换阈值为什么是 8 和 6？1.7 扩容死循环是怎么发生的？</li><li><strong>AQS 原理</strong>：如何用 state + CLH 队列实现独占/共享锁？</li><li><strong>JVM 调优实战</strong>：OOM 怎么排查？CPU 100% 怎么定位？Full GC 频繁如何优化？</li><li><strong>线程池核心参数</strong>：最大线程数和核心线程数的区别？优先入队还是优先创建线程？</li><li><strong>ConcurrentHashMap</strong>：如何实现线程安全？size 如何计算？1.7 分段锁 vs 1.8 CAS+synchronized？</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>只背八股文，没有源码阅读经验，被追问细节时露馅</li><li>对调优参数只会配置，不了解背后的原理</li><li>并发问题停留在理论，没有实际的线上排查经验</li></ul></div><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="阶段一-理论基础-2-周" tabindex="-1">阶段一：理论基础（2 周） <a class="header-anchor" href="#阶段一-理论基础-2-周" aria-label="Permalink to &quot;阶段一：理论基础（2 周）&quot;">​</a></h3><ol><li>通读《深入理解 Java 虚拟机》前三章，配合 IDEA 运行调试</li><li>手写 HashMap 与 ConcurrentHashMap 的核心逻辑（put / get / resize）</li><li>用 jstack / jmap / jstat 实际诊断一个模拟的 OOM 场景</li></ol><h3 id="阶段二-源码深入-3-周" tabindex="-1">阶段二：源码深入（3 周） <a class="header-anchor" href="#阶段二-源码深入-3-周" aria-label="Permalink to &quot;阶段二：源码深入（3 周）&quot;">​</a></h3><ol start="4"><li>阅读 AQS / ReentrantLock / ThreadPoolExecutor 源码，画出关键流程图</li><li>分析 Netty 中 Reactor 主从模型的代码实现</li><li>总结 Spring 源码中使用到的设计模式，每种找一个实例</li></ol><h3 id="阶段三-实战应用-2-周" tabindex="-1">阶段三：实战应用（2 周） <a class="header-anchor" href="#阶段三-实战应用-2-周" aria-label="Permalink to &quot;阶段三：实战应用（2 周）&quot;">​</a></h3><ol start="7"><li>搭建 JMH 基准测试环境，对比不同集合、锁、IO 方式的性能</li><li>模拟线上问题场景：死锁、内存泄漏、接口超时，完整走一遍排查流程</li><li>阅读阿里 Java 开发手册，逐条理解其背后的原理</li></ol><details class="details custom-block"><summary>推荐书单</summary><ul><li>《深入理解 Java 虚拟机（第3版）》—— 周志明</li><li>《Java 并发编程的艺术》—— 方腾飞</li><li>《Java 并发编程实战》—— Brian Goetz</li><li>《Effective Java（第3版）》—— Joshua Bloch</li><li>《Netty 实战》—— Norman Maurer</li><li>《Head First 设计模式》</li></ul></details>',27)])])}const p=a(l,[["render",i]]);export{b as __pageData,p as default};
